"use strict";(self.webpackChunkpos_doc=self.webpackChunkpos_doc||[]).push([[65],{2389(e,t,i){i.r(t),i.d(t,{_pageData:()=>n,default:()=>o});var a=i(641);const n=JSON.parse('{"path":"/woocommerce-pos/pos-agent-guide.html","title":"POS Agent Guide","lang":"en-US","frontmatter":{"title":"POS Agent Guide","description":"Learn how POS agents use the system for sales, customers, checkout, and offline orders.","sidebarPosition":10},"git":{"contributors":[{"name":"himanshu","username":"","email":"himanshu.kumar731@webkul.in","commits":2},{"name":"harshit","username":"","email":"harshit.qa322@webkul.in","commits":2}],"changelog":[{"hash":"e0aac8ca5df6032b25db34a7bd8d20e0c0b22a40","time":1770293899000,"email":"harshit.qa322@webkul.in","author":"harshit","message":"updated doc"},{"hash":"d40e6fdaa8b21bf16d0e572854cf43f79756c0c7","time":1768918927000,"email":"himanshu.kumar731@webkul.in","author":"himanshu","message":"Added: Update Code for POS doc"},{"hash":"0f78e3256fa0d58de79a9cbca0c15a253149691b","time":1767359090000,"email":"harshit.qa322@webkul.in","author":"harshit","message":"updated content file"},{"hash":"16518591e2894732d0b7035818abb4e0c6f620a6","time":1767082527000,"email":"himanshu.kumar731@webkul.in","author":"himanshu","message":"added initial commit"}]},"filePathRelative":"woocommerce-pos/pos-agent-guide.md"}'),r={name:"pos-agent-guide.md"},o=(0,i(6262).A)(r,[["render",function(e,t,i,n,r,o){return(0,a.uX)(),(0,a.CE)("div",null,[...t[0]||(t[0]=[(0,a.Fv)('<p><img src="/pos-for-woocommerce/images/woocommerce-pos/di-5-pos-agent-terminal.webp" alt="POS Dashboard"></p><h1 id="woocommerce-pos-agent-guide-step-by-step-usage" tabindex="-1"><a class="header-anchor" href="#woocommerce-pos-agent-guide-step-by-step-usage"><span>WooCommerce POS - Agent Guide (Step-by-Step Usage)</span></a></h1><h2 id="login-dashboard-overview" tabindex="-1"><a class="header-anchor" href="#login-dashboard-overview"><span>Login &amp; Dashboard Overview</span></a></h2><h3 id="accessing-the-pos-system" tabindex="-1"><a class="header-anchor" href="#accessing-the-pos-system"><span>Accessing the POS System</span></a></h3><p><strong>Login Process:</strong></p><ol><li>POS agent enters login details provided by admin to access front end</li><li>Enter username or email</li><li>Enter password</li><li>Select outlet (if multiple outlets assigned)</li><li>Click <strong>Login</strong> button</li></ol><h3 id="navigation-menu" tabindex="-1"><a class="header-anchor" href="#navigation-menu"><span>Navigation Menu</span></a></h3><p><strong>Left Navigation Drawer</strong> displays menu options:</p><ul><li><strong>Home</strong>: Main dashboard and quick access</li><li><strong>Customer</strong>: Customer management and search</li><li><strong>Cashier</strong>: Point of sale interface and transactions</li><li><strong>Orders</strong>: Order management and history</li><li><strong>Report</strong>: Sales and performance reports</li><li><strong>Group Message</strong>: Broadcast messaging to customers</li><li><strong>Settings</strong>: User preferences and configurations</li><li><strong>Reset</strong>: Data synchronization options</li><li><strong>Logout</strong>: Secure logout from system</li></ul><h3 id="dashboard-features" tabindex="-1"><a class="header-anchor" href="#dashboard-features"><span>Dashboard Features</span></a></h3><p><strong>After Login:</strong></p><ul><li>POS user sees panel with all products assigned to outlet displayed</li><li>Products organized by categories</li><li>Search bar for quick product lookup</li><li>Cart section for order management</li></ul><p><strong>Cart Overview:</strong></p><ul><li>Cart option contains all ordered products by customer</li><li>Real-time total calculation</li><li>Product quantity adjustment</li><li>Quick product removal</li></ul><h3 id="theme-configuration" tabindex="-1"><a class="header-anchor" href="#theme-configuration"><span>Theme Configuration</span></a></h3><p><strong>Dark Theme Setup:</strong></p><ol><li>User can configure dark theme for POS page from POS panel</li><li>Theme switching: Open POS panel &gt; click theme switch in right side corner &gt; change to dark mode</li><li>Toggle between light and dark mode as needed</li><li>Preference saves automatically</li></ol><p><strong>Theme Benefits:</strong></p><ul><li>Reduced eye strain</li><li>Better visibility in different lighting</li><li>Personal preference accommodation</li></ul><h2 id="latest-additions" tabindex="-1"><a class="header-anchor" href="#latest-additions"><span>Latest Additions</span></a></h2><p>The following features were added in the latest update:</p><ul><li>Added: Multi-Pricing of products</li><li>Added: Implemented attribute-based filtering for multiple attribute types, along with support for On Sale and Featured product filters.</li><li>Added: “On Sale” badge for products currently on sale.</li><li>Added: Implemented notification tones for product selection, drawer close actions,keypad tone and payment confirmation to enhance POS user interaction and feedback experience.</li><li>Added: Outlet-wise default tone configuration at the admin end and audio settings at the POS end when tones are enabled.</li><li>Added: Multiple variation card layouts — List View, Table View, and Card View.</li><li>Added: Stock visibility based on the configured Display Stock settings.</li><li>Added: Pin icon visibility settings with options to display the pin Always Visible or On Hover.</li></ul><hr><h2 id="adding-products-to-cart" tabindex="-1"><a class="header-anchor" href="#adding-products-to-cart"><span>Adding Products to Cart</span></a></h2><h3 id="product-search-methods" tabindex="-1"><a class="header-anchor" href="#product-search-methods"><span>Product Search Methods</span></a></h3><p>The POS system offers multiple ways to find and add products quickly.</p><h3 id="_1-search-by-product-name" tabindex="-1"><a class="header-anchor" href="#_1-search-by-product-name"><span>1. Search by Product Name</span></a></h3><p><strong>Using Search Bar:</strong></p><ol><li>Type product name in search bar</li><li>Results appear as you type</li><li>Select desired product from results</li><li>Product automatically adds to cart</li></ol><p><strong>Search Tips:</strong></p><ul><li>Use partial names for quick results</li><li>Search is case-insensitive</li><li>Works with product titles</li></ul><h3 id="_2-category-based-search" tabindex="-1"><a class="header-anchor" href="#_2-category-based-search"><span>2. Category-Based Search</span></a></h3><p><strong>Category Navigation:</strong></p><ol><li>Click on category icon to view category lists</li><li>Browse through available categories</li><li>Select category to choose product</li><li>View products within that category</li><li>Click on product to add to cart</li></ol><p><strong>Category Features:</strong></p><ul><li>Visual category browsing</li><li>Organized product display</li><li>Quick category switching</li></ul><h3 id="_3-sku-based-search" tabindex="-1"><a class="header-anchor" href="#_3-sku-based-search"><span>3. SKU-Based Search</span></a></h3><p><strong>Search by SKU:</strong></p><ol><li>On basis of SKU of product, POS user can search for products</li><li>Enter SKU in search bar</li><li>Exact or partial SKU matching</li><li>Quick product identification</li></ol><p><strong>SKU Search Benefits:</strong></p><ul><li>Faster than name search</li><li>More accurate results</li><li>Useful for inventory management</li></ul><h3 id="_4-barcode-scanning" tabindex="-1"><a class="header-anchor" href="#_4-barcode-scanning"><span>4. Barcode Scanning</span></a></h3><p><strong>Using Barcode Scanner:</strong></p><ol><li>POS users can add product to cart by scanning barcode</li><li>Barcode generated based on SKU or Product ID</li><li>Barcode readers can be used to add products to cart</li><li>Product addition: Add products to cart by both barcodes (product ID or SKU)</li></ol><p><strong>Barcode Scanning Process:</strong></p><ol><li>Aim scanner at barcode</li><li>Press trigger to scan</li><li>Product automatically adds to cart</li><li>Quantity adjustable after adding</li></ol><p><strong>Compatible Barcodes:</strong></p><ul><li>Code-128 format</li><li>SKU-based barcodes</li><li>Product ID-based barcodes</li></ul><h3 id="adding-variable-products" tabindex="-1"><a class="header-anchor" href="#adding-variable-products"><span>Adding Variable Products</span></a></h3><p><strong>Variable Product Workflow:</strong></p><ol><li><strong>Search Main Product</strong>: Search main product using name or SKU in search bar</li><li><strong>Product Selection</strong>: Once main product appears in results</li><li><strong>Variant Selection</strong>: Select variant for customer (size, color, etc.)</li><li><strong>Add to Cart</strong>: Selected variant adds to cart</li></ol><p><strong>Variant Options:</strong></p><ul><li>Size variations</li><li>Color variations</li><li>Material variations</li><li>Any configured product attributes</li></ul><h3 id="adding-custom-products" tabindex="-1"><a class="header-anchor" href="#adding-custom-products"><span>Adding Custom Products</span></a></h3><p><strong>Custom Product Entry:</strong></p><p>For products not available on website but available in physical store:</p><ol><li><strong>Click Plus Sign</strong>: Click plus sign (+) button to add custom product</li><li><strong>Enter Product Details</strong>: <ul><li>Product name</li><li>Product price</li></ul></li><li><strong>Add to Cart</strong>: Click &quot;ADD&quot; button to add custom product to cart</li></ol><p><strong>Custom Product Use Cases:</strong></p><ul><li>Unlisted items</li><li>Special orders</li><li>One-time products</li><li>Emergency inventory</li></ul><hr><h2 id="customer-search-add" tabindex="-1"><a class="header-anchor" href="#customer-search-add"><span>Customer Search/Add</span></a></h2><h3 id="adding-customer-to-order" tabindex="-1"><a class="header-anchor" href="#adding-customer-to-order"><span>Adding Customer to Order</span></a></h3><p><strong>Initial Customer Selection:</strong></p><ol><li>Add customer details: Click on <strong>Default Customer</strong> option after adding products to cart</li><li>Customer selection interface opens</li><li>Search or add new customer</li></ol><h3 id="searching-existing-customers" tabindex="-1"><a class="header-anchor" href="#searching-existing-customers"><span>Searching Existing Customers</span></a></h3><p><strong>Customer Search Options:</strong></p><ul><li>POS users can search for customers by name or email</li><li>Type in search field</li><li>Select from results</li></ul><p><strong>Search Features:</strong></p><ul><li>Real-time search results</li><li>Name-based search</li><li>Email-based search</li><li>Phone number search (if enabled)</li></ul><h3 id="adding-new-customers" tabindex="-1"><a class="header-anchor" href="#adding-new-customers"><span>Adding New Customers</span></a></h3><p><strong>New Customer Entry:</strong></p><ol><li><strong>Enter Customer Details</strong> in customer field: <ul><li>First Name</li><li>Last Name</li><li>Email Address</li><li>Phone Number</li><li>Address (optional)</li></ul></li><li><strong>Save Customer</strong>: Click save or add button</li><li><strong>Customer Selection</strong>: Select customer from customer&#39;s field to pay for order</li></ol><p><strong>Customer Administration:</strong></p><ul><li>Admin can add customers with details like name, email, telephone and address</li><li>Customers saved for future use</li><li>Customer history tracking</li></ul><h3 id="customer-display-in-cart" tabindex="-1"><a class="header-anchor" href="#customer-display-in-cart"><span>Customer Display in Cart</span></a></h3><p><strong>Customer Confirmation:</strong></p><ul><li><strong>Default Customer Tab</strong>: Added customer visible in cart with tab name (e.g., &quot;Johndoe&quot;)</li><li>Customer name displayed prominently</li><li>Easy customer verification</li><li>Quick customer change option</li></ul><hr><h2 id="applying-discounts-coupons" tabindex="-1"><a class="header-anchor" href="#applying-discounts-coupons"><span>Applying Discounts &amp; Coupons</span></a></h2><h3 id="coupon-application" tabindex="-1"><a class="header-anchor" href="#coupon-application"><span>Coupon Application</span></a></h3><p><strong>How to Apply Coupons:</strong></p><ol><li><strong>Coupon Application</strong>: POS agent can apply coupon to cart at time of checkout</li><li><strong>Apply Coupon Button</strong>: Click Apply Coupon button</li><li><strong>Enter Coupon Code</strong>: Type or scan coupon code</li><li><strong>Hit Enter</strong>: Press enter to apply coupon to order</li></ol><p><strong>Coupon Confirmation:</strong></p><ul><li><strong>Coupon applied successfully</strong> pop-up message appears</li><li><strong>Coupon Display</strong>: Shows in cart under &quot;coupon&quot; option</li><li>Discount amount visible in cart total</li></ul><h3 id="manual-discount-application" tabindex="-1"><a class="header-anchor" href="#manual-discount-application"><span>Manual Discount Application</span></a></h3><p><strong>Discount Options:</strong></p><p>Discount application available in two ways:</p><ol><li><strong>Percentage-wise discount</strong></li><li><strong>Flat Discount</strong> (fixed amount)</li></ol><p><strong>Applying Discount:</strong></p><ol><li><strong>&quot;Apply discount to sale&quot;</strong> appears on clicking &quot;Discount&quot; option in cart</li><li><strong>Select Discount Type</strong>: <ul><li><strong>Percentage discount</strong>: Select &quot;%&quot; option to tabulate discount on percentage basis</li><li><strong>Flat discount</strong>: Enter fixed amount</li></ul></li><li><strong>Apply Discount</strong>: Discount applies to cart</li><li><strong>Grand Total</strong>: Displays discounted amount</li></ol><h3 id="customer-based-discounts" tabindex="-1"><a class="header-anchor" href="#customer-based-discounts"><span>Customer-Based Discounts</span></a></h3><p><strong>Automatic Discounts:</strong></p><ul><li><strong>Customer-based discount</strong>: Applicable for few products</li><li>Discount applies automatically when customer selected</li><li>Based on customer group membership</li><li>No manual intervention needed</li></ul><p><strong>Discount Features:</strong></p><ul><li>Loyalty pricing</li><li>VIP customer discounts</li><li>Member pricing</li><li>Group-specific offers</li></ul><h3 id="price-editing" tabindex="-1"><a class="header-anchor" href="#price-editing"><span>Price Editing</span></a></h3><p><strong>Manual Price Adjustment:</strong></p><ul><li><strong>Price editing</strong>: POS user can edit price of items in cart</li><li>Click on price to edit</li><li>Enter new price</li><li>Confirm change</li><li>Useful for special circumstances</li></ul><hr><h2 id="payment-processing" tabindex="-1"><a class="header-anchor" href="#payment-processing"><span>Payment Processing</span></a></h2><h3 id="available-payment-options" tabindex="-1"><a class="header-anchor" href="#available-payment-options"><span>Available Payment Options</span></a></h3><p><strong>Payment Methods:</strong></p><p>The system supports multiple payment methods:</p><ul><li><strong>Cash Payment</strong>: Primary payment method</li><li><strong>Other Payment</strong>: Includes all payment methods enabled by admin such as: <ul><li>Paypal</li><li>Sunmi Terminal credit/debit card</li><li>Custom payment gateways</li><li>Digital wallets</li></ul></li></ul><h3 id="split-payment-feature" tabindex="-1"><a class="header-anchor" href="#split-payment-feature"><span>Split Payment Feature</span></a></h3><p><strong>Multiple Payment Methods:</strong></p><ul><li><strong>Split Payment</strong>: Customer can pay money in cash as well as any other payment method</li><li><strong>Payment Acceptance</strong>: Cash, via card, or split payment between card and cash</li><li>Example: Part cash, part card for same transaction</li></ul><p><strong>Split Payment Process:</strong></p><ol><li>Select first payment method</li><li>Enter amount for first method</li><li>Select second payment method</li><li>Remaining amount automatically calculated</li><li>Complete transaction</li></ol><h3 id="payment-recording" tabindex="-1"><a class="header-anchor" href="#payment-recording"><span>Payment Recording</span></a></h3><p><strong>Transaction Tracking:</strong></p><ul><li>Monetary transactions done outside system</li><li>POS records payment method used</li><li>Payment details stored for reporting</li><li>Reconciliation support</li></ul><h3 id="payment-view-options" tabindex="-1"><a class="header-anchor" href="#payment-view-options"><span>Payment View Options</span></a></h3><p><strong>Other Payment Display Views:</strong></p><p>Choose from three display options for payment methods:</p><ol><li><strong>Grid View Listing</strong>: Normal grid view with payment method tiles</li><li><strong>Grid With Currency Listing</strong>: Grid view with currency icon visible on each payment option</li><li><strong>Dropdown-listing</strong>: Dropdown menu for payment method selection</li></ol><p><strong>Selecting View:</strong></p><ul><li>Configure in settings</li><li>Choose preferred layout</li><li>Optimize for screen size</li><li>Personal preference</li></ul><h3 id="completing-payment" tabindex="-1"><a class="header-anchor" href="#completing-payment"><span>Completing Payment</span></a></h3><p><strong>Checkout Process:</strong></p><ol><li>Review cart contents</li><li>Verify customer details</li><li>Apply discounts/coupons if applicable</li><li>Select payment method(s)</li><li>Enter payment amount(s)</li><li>Process payment</li><li>Generate receipt</li></ol><hr><h2 id="printing-invoices" tabindex="-1"><a class="header-anchor" href="#printing-invoices"><span>Printing Invoices</span></a></h2><h3 id="invoice-printing-overview" tabindex="-1"><a class="header-anchor" href="#invoice-printing-overview"><span>Invoice Printing Overview</span></a></h3><p><strong>Receipt Generation:</strong></p><ul><li>Invoice printing: User can print invoice for order</li><li>Automatic or manual printing</li><li>Multiple printer support</li></ul><h3 id="invoice-configuration" tabindex="-1"><a class="header-anchor" href="#invoice-configuration"><span>Invoice Configuration</span></a></h3><p><strong>Admin Settings:</strong></p><ul><li><strong>POS Invoice Option</strong>: Admin can select enable/disable to print POS invoices for orders</li><li>Configure default printer</li><li>Set auto-print preferences</li></ul><h3 id="selecting-printer" tabindex="-1"><a class="header-anchor" href="#selecting-printer"><span>Selecting Printer</span></a></h3><p><strong>Printer Options:</strong></p><p>POS agent may choose printer option:</p><ul><li><strong>A3</strong>: Large format paper</li><li><strong>A4</strong>: Standard paper size</li><li><strong>A5</strong>: Half A4 size</li><li><strong>Epson TM-T88V Thermal Printer</strong>: Receipt printer</li><li><strong>A6</strong>: Small format (common for receipts)</li></ul><p><strong>Printer Selection:</strong></p><ol><li>Click printer icon or settings</li><li>Select desired printer type</li><li>Preview invoice</li><li>Print</li></ol><h3 id="auto-print-feature" tabindex="-1"><a class="header-anchor" href="#auto-print-feature"><span>Auto-Print Feature</span></a></h3><p><strong>Automatic Printing:</strong></p><ul><li><strong>Auto-print setting</strong>: Introduced auto-print enable/disable setting for POS users</li><li>Configure to print automatically after each sale</li><li>Enable/disable per user preference</li><li>Saves time during busy periods</li></ul><h3 id="email-receipts" tabindex="-1"><a class="header-anchor" href="#email-receipts"><span>Email Receipts</span></a></h3><p><strong>Digital Receipt Options:</strong></p><ul><li><strong>Order receipt</strong>: Admin can send order receipt manually via email after order completion</li><li>Email to customer address</li><li>Backup receipt option</li><li>Environmental alternative to paper</li></ul><p><strong>Email Process:</strong></p><ol><li>Complete transaction</li><li>Click email receipt option</li><li>Verify customer email</li><li>Send receipt</li></ol><hr><h2 id="managing-returns" tabindex="-1"><a class="header-anchor" href="#managing-returns"><span>Managing Returns</span></a></h2><h3 id="viewing-refund-information" tabindex="-1"><a class="header-anchor" href="#viewing-refund-information"><span>Viewing Refund Information</span></a></h3><p><strong>Refund Visibility:</strong></p><ul><li><strong>Refund visibility</strong>: WooCommerce website order refund details visible at POS</li><li>Real-time refund synchronization</li><li>Complete refund information</li></ul><h3 id="processing-refunds" tabindex="-1"><a class="header-anchor" href="#processing-refunds"><span>Processing Refunds</span></a></h3><p><strong>Refund Details:</strong></p><ul><li><strong>Refund initiation</strong>: If refund initiates for WooCommerce website order by admin, refund details visible at POS for particular order</li><li>View refund amount</li><li>See refund method</li><li>Track refund status</li></ul><p><strong>Refund Information Display:</strong></p><ul><li>Original order details</li><li>Refund amount</li><li>Refund date and time</li><li>Refund reason (if provided)</li><li>Refund method (original payment method)</li></ul><h3 id="return-process" tabindex="-1"><a class="header-anchor" href="#return-process"><span>Return Process</span></a></h3><p><strong>Steps for Returns:</strong></p><ol><li>Search for original order</li><li>View order details</li><li>Check refund status</li><li>Process in-store return if applicable</li><li>Update inventory</li><li>Complete refund transaction</li></ol><hr><h2 id="daily-closing-procedures" tabindex="-1"><a class="header-anchor" href="#daily-closing-procedures"><span>Daily Closing Procedures</span></a></h2><h3 id="accessing-close-counter" tabindex="-1"><a class="header-anchor" href="#accessing-close-counter"><span>Accessing Close Counter</span></a></h3><p><strong>Navigation:</strong></p><ul><li><strong>Close Counter tab</strong>: Available under <strong>Cashier</strong> section</li><li>End-of-day reconciliation</li><li>Cash drawer management</li></ul><h3 id="closing-cash-drawer" tabindex="-1"><a class="header-anchor" href="#closing-cash-drawer"><span>Closing Cash Drawer</span></a></h3><p><strong>End of Day Process:</strong></p><ul><li><strong>Drawer closure</strong>: POS agent closes cash drawer at end of day</li><li>Complete reconciliation required</li><li>Accurate counting essential</li></ul><h3 id="drawer-amount-details" tabindex="-1"><a class="header-anchor" href="#drawer-amount-details"><span>Drawer Amount Details</span></a></h3><p>The <strong>Drawer Amount Details</strong> panel presents a clear ledger of the shift&#39;s starting and ending figures:</p><table><thead><tr><th style="text-align:left;">Metric Name</th><th style="text-align:left;">Value Example</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Opening Amount</strong></td><td style="text-align:left;"><code>$1,000.00</code></td><td style="text-align:left;">The starting cash float placed in the drawer at the beginning of the shift.</td></tr><tr><td style="text-align:left;"><strong>Today&#39;s Sales</strong></td><td style="text-align:left;"><code>$2,500.00</code></td><td style="text-align:left;">The cumulative total of all cash transactions completed during the current shift.</td></tr><tr><td style="text-align:left;"><strong>Expected Amount</strong></td><td style="text-align:left;"><code>$3,500.00</code></td><td style="text-align:left;">The calculated sum of the opening float plus today&#39;s cash sales (<code>Opening Amount + Today&#39;s Sales</code>).</td></tr></tbody></table><h3 id="counted-drawer-amount" tabindex="-1"><a class="header-anchor" href="#counted-drawer-amount"><span>Counted Drawer Amount</span></a></h3><p><strong>Physical Count Entry:</strong></p><ul><li><strong>Counted Drawer Amount</strong>: Cash amount collected for particular day</li><li>Count all cash in drawer</li><li>Enter counted amount</li><li>Add remarks if needed</li></ul><p><strong>Counting Tips:</strong></p><ul><li>Count carefully</li><li>Separate denominations</li><li>Double-check total</li><li>Note any discrepancies</li></ul><h3 id="closing-drawer-details" tabindex="-1"><a class="header-anchor" href="#closing-drawer-details"><span>Closing Drawer Details</span></a></h3><p><strong>Reconciliation Summary:</strong></p><ul><li><strong>Closing Drawer Details</strong>: Closing balance details for particular day</li><li><strong>Difference viewing</strong>: Between opening and closing amount under Closing Drawer Details</li><li>Shows over/short amount</li><li>Requires explanation for variances</li></ul><p><strong>Closing Information:</strong></p><ul><li>Expected closing amount</li><li>Actual counted amount</li><li>Difference (+ or -)</li><li>Remarks field</li></ul><h3 id="today-cash-option" tabindex="-1"><a class="header-anchor" href="#today-cash-option"><span>Today Cash Option</span></a></h3><p>The <strong>Today Cash</strong> view displays real-time cash flow metrics:</p><table><thead><tr><th style="text-align:left;">Balance Type</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Cash Opening Balance</strong></td><td style="text-align:left;">The starting float amount entered when opening the register.</td></tr><tr><td style="text-align:left;"><strong>Current Cash Balance</strong></td><td style="text-align:left;">The live, real-time total of cash currently available in the drawer.</td></tr><tr><td style="text-align:left;"><strong>Current Card Balance</strong></td><td style="text-align:left;">The total volume of transactions processed via credit/debit card.</td></tr></tbody></table><p><strong>Real-time Updates:</strong></p><ul><li>Updates with each transaction</li><li>Track cash flow throughout day</li><li>Monitor payment distribution</li></ul><h3 id="sale-history" tabindex="-1"><a class="header-anchor" href="#sale-history"><span>Sale History</span></a></h3><p>The <strong>Sale History</strong> sub-tab under the Cashier section offers a historical breakdown of finalized register sessions:</p><table><thead><tr><th style="text-align:left;">Metric / Field</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Particular Date</strong></td><td style="text-align:left;">The selected calendar date for which sales data is being viewed.</td></tr><tr><td style="text-align:left;"><strong>Cash Sale</strong></td><td style="text-align:left;">Total cash transactions recorded on the selected date.</td></tr><tr><td style="text-align:left;"><strong>Card Sale</strong></td><td style="text-align:left;">Total card transactions processed on the selected date.</td></tr><tr><td style="text-align:left;"><strong>Total Sale Display</strong></td><td style="text-align:left;">The combined revenue of both cash and card sales on that date.</td></tr></tbody></table><blockquote><p>[!NOTE] Historical details in the <strong>Sale History</strong> screen are populated only after the cash drawer session has been successfully closed via the <strong>Close Counter</strong> screen.</p></blockquote><h3 id="completing-daily-close" tabindex="-1"><a class="header-anchor" href="#completing-daily-close"><span>Completing Daily Close</span></a></h3><p><strong>Final Steps:</strong></p><ol><li>Review all sales for the day</li><li>Count cash drawer</li><li>Enter counted amount</li><li>Review discrepancies</li><li>Add remarks if needed</li><li>Submit drawer close</li><li>Print/email closing report</li><li>Secure cash for deposit</li></ol><hr>',190)])])}]])}}]);